use axum::{extract::{Path, Query, State}, http::StatusCode, Json};

pub async fn list(
    State(state): State<AppState>,
    Query(params): Query<ListParams>,
) -> Result<Json<ListResponse>, AppError> {
    let svc = UserService::new(&state.db);
    let (users, total) = svc.list(params.page, params.per_page).await?;
    Ok(Json(ListResponse {
        data: users.into_iter().map(UserResponse::from).collect(),
        total, page: params.page, per_page: params.per_page,
    }))
}

pub async fn create(
    State(state): State<AppState>,
    Json(payload): Json<CreateUserRequest>,
) -> Result<(StatusCode, Json<UserResponse>), AppError> {
    payload.validate()?;
    let svc = UserService::new(&state.db);
    let user = svc.create(&payload.name, &payload.email, &payload.password).await?;
    Ok((StatusCode::CREATED, Json(user.into())))
}

pub async fn list(&self, page: u32, per_page: u32) -> Result<(Vec<User>, i64), AppError> {
    let offset = ((page - 1) * per_page) as i64;
    let (users, total) = tokio::try_join!(
        self.db.fetch_users(per_page as i64, offset),
        self.db.count_users()
    )?;
    Ok((users, total))
}

pub async fn create(&self, name: &str, email: &str, password: &str) -> Result<User, AppError> {
    if self.db.fetch_user_by_email(email).await?.is_some() {
        return Err(AppError::Conflict("Email already exists".into()));
    }
    let pw = password.to_string();
    let hash = tokio::task::spawn_blocking(move || {
        let salt = SaltString::generate(&mut OsRng);
        Argon2::default().hash_password(pw.as_bytes(), &salt).map(|h| h.to_string())
    }).await??;
    self.db.insert_user(name, email, &hash).await
}

use futures::stream::{self, StreamExt};
use tokio::sync::Semaphore;

pub async fn process_batch<T, F, Fut, R>(
    items: Vec<T>, limit: usize, f: F,
) -> Vec<R>
where
    T: Send + 'static,
    F: Fn(T) -> Fut + Send + Sync + 'static,
    Fut: std::future::Future<Output = R> + Send,
    R: Send + 'static,
{
    let sem = Arc::new(Semaphore::new(limit));
    let f = Arc::new(f);
    stream::iter(items)
        .map(|item| {
            let sem = sem.clone(); let f = f.clone();
            async move { let _p = sem.acquire().await.unwrap(); f(item).await }
        })
        .buffer_unordered(limit)
        .collect()
        .await
}
